import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import axios from "axios";

const API = process.env.REACT_APP_API_BASE;

export default function UploadBills() {
  const navigate = useNavigate();
  const empId = sessionStorage.getItem("empld");

  const [files, setFiles] = useState([]);
  const [bills, setBills] = useState([]);

  // Load bills
  const loadBills = async () => {
    try {
      const res = await axios.get(`${API}/bills/${empId}`);
      setBills(res.data.bills || []);
    } catch (err) {
      console.log("FETCH BILLS ERROR:", err);
    }
  };

  useEffect(() => {
    loadBills();
  }, []);

  const uploadBills = async () => {
    if (!files.length) return alert("Select files first!");

    const formData = new FormData();
    for (let f of files) formData.append("files", f);
    formData.append("empId", empId);

    try {
      await axios.post(`${API}/bills/upload`, formData);
      alert("Bills uploaded successfully!");
      loadBills();
    } catch (err) {
      alert("Upload failed!");
    }
  };

  const deleteBill = async (id) => {
    if (!window.confirm("Delete this bill?")) return;

    try {
      await axios.delete(`${API}/bills/delete/${id}`);
      loadBills();
    } catch (err) {
      console.log("DELETE ERROR:", err);
    }
  };

  const downloadReport = () => {
    window.open(`${API}/bills/report/${empId}`, "_blank");
  };

  return (
    <div
      style={{
        minHeight: "100vh",
        paddingTop: "40px",
        background: "#eaf8f0",
        display: "flex",
        justifyContent: "center",
      }}
    >
      <div
        style={{
          width: "92%",
          maxWidth: "900px",
          background: "white",
          padding: "25px",
          borderRadius: "20px",
          boxShadow: "0px 4px 12px rgba(0,0,0,0.1)",
        }}
      >
        {/* Back Arrow + Title */}
        <div style={{ display: "flex", alignItems: "center", marginBottom: "15px" }}>
          <button
            onClick={() => navigate(-1)}
            style={{
              background: "white",
              border: "2px solid #0f9d58",
              color: "#0f9d58",
              width: "46px",
              height: "46px",
              borderRadius: "12px",
              fontSize: "22px",
              cursor: "pointer",
              marginRight: "15px",
            }}
          >
            ←
          </button>

          <h2 style={{ color: "#0f9d58", fontWeight: "700", fontSize: "26px" }}>
            Upload Bills History
          </h2>
        </div>

        {/* Employee Info */}
        <p style={{ marginLeft: "5px", color: "#444" }}>
          Employee: Laxmi Patil • <b>{empId}</b>
        </p>

        {/* Upload section box */}
        <div
          style={{
            background: "#f0faF4",
            padding: "20px",
            borderRadius: "12px",
            marginTop: "25px",
            marginBottom: "25px",
          }}
        >
          <label style={{ fontWeight: "600", color: "#333" }}>Upload Bills</label>

          <div style={{ marginTop: "12px", display: "flex", alignItems: "center" }}>
            <input
              type="file"
              multiple
              onChange={(e) => setFiles(e.target.files)}
              style={{
                padding: "10px",
                borderRadius: "10px",
                border: "1px solid #ccc",
                fontSize: "14px",
                width: "70%",
              }}
            />

            <button
              onClick={uploadBills}
              style={{
                marginLeft: "12px",
                background: "#0f9d58",
                color: "white",
                padding: "12px 20px",
                borderRadius: "10px",
                border: "none",
                cursor: "pointer",
                fontWeight: "600",
              }}
            >
              Upload
            </button>
          </div>
        </div>

        {/* TABLE EXACT MATCH TO TRAVEL/TICKET */}
        <table
          style={{
            width: "100%",
            borderCollapse: "collapse",
            marginTop: "10px",
          }}
        >
          <thead>
            <tr style={{ background: "#eaf8f0" }}>
              <th style={th}>Date</th>
              <th style={th}>File Name</th>
              <th style={th}>Preview</th>
              <th style={th}>Delete</th>
            </tr>
          </thead>

          <tbody>
            {bills.length === 0 ? (
              <tr>
                <td colSpan="4" style={noData}>No bills uploaded</td>
              </tr>
            ) : (
              bills.map((b) => (
                <tr key={b.id}>
                  <td style={td}>
                    {new Date(b.uploaded_at).toLocaleDateString()}
                  </td>
                  <td style={td}>{b.file_name}</td>

                  <td style={td}>
                    <a
                      href={b.file_path}
                      target="_blank"
                      rel="noreferrer"
                      style={{ color: "#0f9d58", fontWeight: "600" }}
                    >
                      View
                    </a>
                  </td>

                  <td style={td}>
                    <button
                      onClick={() => deleteBill(b.id)}
                      style={deleteBtn}
                    >
                      Delete
                    </button>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>

        {/* DOWNLOAD REPORT */}
        <button onClick={downloadReport} style={downloadBtn}>
          📄 Download Monthly Bills Report
        </button>
      </div>
    </div>
  );
}

/* Styles */
const th = {
  padding: "12px",
  fontWeight: "700",
  fontSize: "15px",
};

const td = {
  padding: "12px",
  borderBottom: "1px solid #eee",
  fontSize: "15px",
};

const noData = {
  padding: "20px",
  textAlign: "center",
  color: "#777",
  fontSize: "16px",
};

const deleteBtn = {
  background: "#e53935",
  padding: "6px 12px",
  borderRadius: "8px",
  color: "white",
  border: "none",
  cursor: "pointer",
  fontSize: "14px",
};

const downloadBtn = {
  background: "#0f9d58",
  padding: "14px 22px",
  borderRadius: "10px",
  color: "white",
  border: "none",
  marginTop: "25px",
  fontSize: "16px",
  fontWeight: "600",
  cursor: "pointer",
};
